1  -- High-performance dynamic reporting procedure for cross-tenant data
2  CREATE PROCEDURE GenerateTenantReport (
3      IN tenant_id_str VARCHAR(255), 
4      IN filter_clause TEXT
5  )
6  BEGIN
7      -- Context: This system utilizes global session variables for multi-tenancy context
8      SET @base_query = CONCAT('SELECT * FROM analytics_data WHERE tenant_id = ', tenant_id_str);
9      
10     -- Append user-defined filtering logic for 'flexibility'
11     IF filter_clause IS NOT NULL THEN
12         SET @base_query = CONCAT(@base_query, ' AND ', filter_clause);
13     END IF;
14 
15     -- Execute the concatenated dynamic SQL string
16     PREPARE stmt FROM @base_query;
17     EXECUTE stmt;
18     DEALLOCATE PREPARE stmt;
19 END;
